using System;using System.Collections.Generic;using System.Linq;class A{static int W,H,turn;static bool[,]wall;static List<int[]>nodes=new(),bombs=new();static int[][]prev;static int[]Mv(int[]n){int x=n[0],y=n[1],dx=n[2],dy=n[3];if(dx==0&&dy==0)return new[]{x,y,dx,dy};int nx=x+dx,ny=y+dy;if(nx<0||nx>=W||ny<0||ny>=H||wall[ny,nx]){dx=-dx;dy=-dy;nx=x+dx;ny=y+dy;}return new[]{nx,ny,dx,dy};}static List<int[]>Sim(List<int[]>ns,int t){var c=ns.Select(n=>(int[])n.Clone()).ToList();for(int i=0;i<t;i++)c=c.Select(Mv).ToList();return c;}static HashSet<int>Blast(int bx,int by){var r=new HashSet<int>{by*W+bx};int[]dx={0,0,1,-1},dy={1,-1,0,0};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int cx=bx+dx[d]*i,cy=by+dy[d]*i;if(cx<0||cx>=W||cy<0||cy>=H||wall[cy,cx])break;r.Add(cy*W+cx);}return r;}static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);wall=new bool[H,W];for(;;){p=Console.ReadLine().Split(' ');int rl=int.Parse(p[0]),ba=int.Parse(p[1]);var cur=new List<int[]>();var grid=new string[H];for(int y=0;y<H;y++){grid[y]=Console.ReadLine();for(int x=0;x<W;x++){if(turn==0&&grid[y][x]=='#')wall[y,x]=true;if(grid[y][x]=='@')cur.Add(new[]{x,y});}}if(turn==0){nodes=cur.Select(c=>new[]{c[0],c[1],0,0}).ToList();prev=cur.ToArray();}else if(turn==1){var used=new HashSet<int>();var nn=new List<int[]>();foreach(var pr in prev){int best=-1,bd=99;for(int i=0;i<cur.Count;i++){if(used.Contains(i))continue;int d=Math.Abs(cur[i][0]-pr[0])+Math.Abs(cur[i][1]-pr[1]);if(d<bd){bd=d;best=i;}}if(best>=0&&bd<=1){used.Add(best);nn.Add(new[]{cur[best][0],cur[best][1],cur[best][0]-pr[0],cur[best][1]-pr[1]});}}for(int i=0;i<cur.Count;i++)if(!used.Contains(i))nn.Add(new[]{cur[i][0],cur[i][1],0,0});nodes=nn;}else{var um=new Dictionary<int,int[]>();foreach(var c in cur)um[c[1]*W+c[0]]=c;var nn=new List<int[]>();foreach(var n in nodes){var m=Mv(n);int k=m[1]*W+m[0];if(um.ContainsKey(k)){nn.Add(m);um.Remove(k);}}foreach(var v in um.Values)nn.Add(new[]{v[0],v[1],0,0});nodes=nn;}foreach(var b in bombs)b[2]--;bool ch=true;while(ch){ch=false;for(int i=bombs.Count-1;i>=0;i--)if(bombs[i][2]<=0){var cells=Blast(bombs[i][0],bombs[i][1]);bombs.RemoveAt(i);nodes.RemoveAll(n=>cells.Contains(n[1]*W+n[0]));foreach(var b in bombs)if(cells.Contains(b[1]*W+b[0]))b[2]=0;ch=true;}}if(ba==0||nodes.Count==0||turn==0){Console.WriteLine("WAIT");Console.Out.Flush();prev=cur.ToArray();turn++;continue;}int mw=Math.Min(rl-4,55),bw=-1,bx=-1,by=-1,bh=0;for(int w=0;w<=mw;w++){var ab=Sim(nodes,w+3);var ap=w>0?Sim(nodes,w):null;var cs=new Dictionary<int,int>();foreach(var n in ab)foreach(var c in Blast(n[0],n[1])){cs.TryGetValue(c,out int v);cs[c]=v+1;}var ps=ap!=null?new HashSet<int>(ap.Select(n=>n[1]*W+n[0])):null;foreach(var e in cs){if(e.Value<=bh)continue;int x=e.Key%W,y=e.Key/W;if(wall[y,x])continue;if(w==0&&grid[y][x]!='.')continue;if(ps!=null&&ps.Contains(e.Key))continue;if(bombs.Any(b=>b[0]==x&&b[1]==y))continue;bh=e.Value;bw=w;bx=x;by=y;}if(bh>=nodes.Count)break;}if(bw==0&&bh>0){bombs.Add(new[]{bx,by,3});Console.WriteLine($"{bx} {by}");}else Console.WriteLine("WAIT");Console.Out.Flush();turn++;}}}